html:
{%
	const report_columns = report
		.get_columns_for_print()
		.filter(col => !col.hidden);

	if (report_columns.length > 8) {
		frappe.throw(
			__("Too many columns. Export the report and print it using a spreadsheet application.")
		);
	}
%}

<style>
	body, html {
		margin-top: 10px;
		padding: 0;
		width: 100%;
		height: auto;
		font-family: Inter, sans-serif;
		font-size: 14px;
		line-height: 21px;
		color: #171717;
	}

	.title-letter-spacing {
		font-size: 14px;
		font-weight: 600;
		color: #171717;
	}

	.financial-statements-important td {
		font-weight: bold;
	}

	.financial-statements-blank-row td {
		height: 43px;
	}

	.report-meta {
		margin: 10px 0 14px;
		padding: 8px 10px;
		display: flex;
		justify-content: space-between;
		align-items: flex-start;
		gap: 12px;
		font-size: 14px;
		color: #171717;
	}

	.report-meta .left,
	.report-meta .right {
		display: flex;
		flex-direction: column;
	}

	.report-meta strong {
		color: #7c7c7c;
		font-weight: 500;
	}

	.report-subtitle {
		margin: 10px 0 14px;
	}

	.text-center {
		text-align: center;
	}

	.text-right {
		text-align: right;
		font-variant-numeric: tabular-nums;
		white-space: nowrap;
		overflow: hidden;
		text-overflow: ellipsis;
	}

	.text-left {
		text-align: left;
	}

	.text-bold {
		font-weight: 700;
	}

	.text-muted {
		color: #7c7c7c;
	}

	.report-table table {
		width: 100%;
		table-layout: fixed;
		border-collapse: separate;
		border-spacing: 0;
	}

	.report-table th,
	.report-table td {
		padding: 6px 8px;
		font-size: 14px;
		border-bottom: 1px solid #ededed;
	}

	.report-table thead th {
		background: #f8f8f8;
		font-weight: 500;
		color: #7c7c7c;
		border-top: 1px solid #ededed;
		border-bottom: 1px solid #ededed;
	}

	.report-table tbody td.text-left {
		vertical-align: top;
		word-wrap: break-word;
	}

	.report-table thead tr:first-child th:first-child {
		border-left: 1px solid #ededed;
		border-top-left-radius: 10px;
		border-bottom-left-radius: 10px;
	}

	.report-table thead tr:first-child th:last-child {
		border-right: 1px solid #ededed;
		border-top-right-radius: 10px;
		border-bottom-right-radius: 10px;
	}

	.report-table tbody tr:last-child td {
		border-bottom: none;
	}

	.report-table tbody tr {
		height: 43px;
	}

	@media print {
		@page {
			size: A4;
			margin-top: 10mm;
		}

		thead {
			display: table-header-group;
		}

		tr {
			page-break-inside: avoid;
		}
	}
</style>

<div>

	<div class="text-center" style="margin-bottom: 12px;">
		<div class="title-letter-spacing">
			{%= __(report.report_name) %}
		</div>
	</div>

    {% if (subtitle && subtitle.trim()) { %}
        <div class="report-subtitle">
            {{ subtitle }}
        </div>
    {% } else { %}
        <div class="report-meta">
            <div class="left">
                <div>
                    <strong>{%= __("Company") %}:</strong> {%= filters.company %}
                </div>
                <div>
                    <strong>{%= __("Currency") %}:</strong>
                    {%= filters.presentation_currency || erpnext.get_currency(filters.company) %}
                </div>
            </div>

            <div class="right text-right">
                <div>
                    <strong>{%= __("From Date") %}:</strong>
                    {%= frappe.datetime.str_to_user(filters.from_date) %}
                </div>
                <div>
                    <strong>{%= __("To Date") %}:</strong>
                    {%= frappe.datetime.str_to_user(filters.to_date) %}
                </div>
            </div>
        </div>
    {% } %}

	<div class="report-table">
    	<table>
    		<thead>
    			<tr>
    				{% for (let i = 0, l = report_columns.length; i < l; i++) { %}
    					{%
    						const col = report_columns[i];
    						const align = i === 0 ? "text-left" : "text-right";
    						const styling = i === 0 ? "" : "width: 9em";
    					%}
    					<th class="{%= align %}" style= "{%= styling%}">
    						{%= col.label %}
    					</th>
    				{% } %}
    			</tr>
    		</thead>

    		<tbody>
    			{% for (let j = 0, k = data.length; j < k; j++) { %}
    				{%
    					const row = data[j];

    					let row_class = "";
    					if (!(row.parent_account || row.parent_section)) {
    						row_class = "financial-statements-important";
    					}
    					if (!(row.account_name || row.section)) {
    						row_class += " financial-statements-blank-row";
    					}
    				%}

    				<tr class="{%= row_class %}">
    					{% for (let i = 0, l = report_columns.length; i < l; i++) { %}
    						{%
    							const col = report_columns[i];
    							const value = row[col.fieldname];
    							const align = i === 0 ? "text-left" : "text-right";
    						%}

    						<td class="{%= align %}">
    							{% if (i === 0) { %}
    								<span style="padding-left: {%= cint(row.indent) * 2 %}em">
    									{%= String(row.account_name || row.section || "").replace(/^['"]|['"]$/g, "") %}
    								</span>
    							{% } else if (!is_null(value)) { %}
    								{%= frappe.format(value, col, {}, row) %}
    							{% } %}
    						</td>
    					{% } %}
    				</tr>
    			{% } %}
    		</tbody>
    	</table>
    </div>

	<p class="text-right text-muted">
		{%= __("Printed on {0}", [
			frappe.datetime.str_to_user(frappe.datetime.get_datetime_as_string())
		]) %}
	</p>

</div>
